    #[test]
    fn cq_portfolio_gate_is_static_and_explainable() {
        let (_, cascade) = temporal_composition_formula("cascade4", 9, 137).unwrap();
        let dense = cq_portfolio_decision(&cascade, 9, 137, 50, 5.0).unwrap();
        assert!(dense.specialized);
        assert_eq!(dense.reason, "dense-transition");
        assert!(
            !cq_portfolio_decision(&cascade, 9, 137, 7, 5.0)
                .unwrap()
                .specialized
        );
        assert!(
            !cq_portfolio_decision(&cascade, 9, 137, 50, 10.0)
                .unwrap()
                .specialized
        );
        let (_, wide_cascade) = temporal_composition_formula("cascade4", 10, 137).unwrap();
        assert!(
            !cq_portfolio_decision(&wide_cascade, 10, 137, 50, 5.0)
                .unwrap()
                .specialized
        );

        let (_, hub) = temporal_composition_formula("hub3", 7, 137).unwrap();
        let narrow_hub = cq_portfolio_decision(&hub, 7, 137, 128, 5.0).unwrap();
        assert!(narrow_hub.specialized);
        assert_eq!(narrow_hub.reason, "narrow-hub");
        assert!(
            !cq_portfolio_decision(&hub, 7, 137, 127, 5.0)
                .unwrap()
                .specialized
        );

        let (_, tree_short) = temporal_composition_formula("tree3", 9, 137).unwrap();
        let fallback = cq_portfolio_decision(&tree_short, 9, 137, 50, 5.0).unwrap();
        assert!(!fallback.specialized);
        assert_eq!(fallback.reason, "cdcl-fallback");

        let (_, tree_long) = temporal_composition_formula("tree3", 11, 1_333).unwrap();
        let conservative_fallback = cq_portfolio_decision(&tree_long, 11, 1_333, 50, 5.0).unwrap();
        assert!(!conservative_fallback.specialized);
        assert_eq!(conservative_fallback.reason, "cdcl-fallback");

        let (_, watchdog) = temporal_composition_formula("watchdog4", 9, 137).unwrap();
        assert_eq!(
            cq_portfolio_decision(&watchdog, 9, 137, 50, 5.0)
                .unwrap()
                .reason,
            "dense-transition"
        );
        let (_, sensor_vote) = temporal_composition_formula("sensor-vote3", 8, 257).unwrap();
        assert_eq!(
            cq_portfolio_decision(&sensor_vote, 8, 257, 50, 5.0)
                .unwrap()
                .reason,
            "cdcl-fallback"
        );
    }

    #[test]
    fn ascii_aiger_import_preserves_transition_and_initial_state() {
        let path =
            std::env::temp_dir().join(format!("cq-sat-aiger-import-{}.aag", std::process::id()));
        fs::write(
            &path,
            "aag 5 0 4 1 1\n2 4\n4 6\n6 8\n8 10\n8\n10 2 5\nc\nsmall closed sequential model\n",
        )
        .unwrap();
        let model = parse_aag(&path).unwrap();
        std::fs::remove_file(path).unwrap();
        assert_eq!(model.latches.len(), 4);
        assert_eq!(model.outputs, vec![8]);
        let (variables, formula, initial) = aag_temporal_formula(&model, 3).unwrap();
        assert_eq!(variables, 16);
        assert_eq!(initial, vec![Some(false); 4]);
        assert!(
            cq_portfolio_decision(&formula, 4, 3, 8, 2.0)
                .unwrap()
                .specialized
        );

        let transition = SymbolicTemporalTransition::recognize(&formula, 4, 3).unwrap();
        let mut assumptions = vec![None; variables];
        assumptions[..4].copy_from_slice(&initial);
        let assignment = transition.query(&assumptions).unwrap();
        assert!(assignment.iter().all(|value| !value));
        assert!(satisfies(&formula, &assignment));
    }

    fn binary_aiger_fixture() -> Vec<u8> {
        let mut bytes = b"aig 4 2 1 1 1\n6 0\n8\n".to_vec();
        // lhs=8, rhs0=4, rhs1=2; binary AIGER stores the two deltas.
        bytes.extend([4, 2]);
        bytes.extend_from_slice(
            b"i0 left_request\ni1 right_request\nl0 state\no0 simultaneous_request\nc\nfixture\n",
        );
        bytes
    }

    fn wide_sparse_aiger_fixture() -> Vec<u8> {
        let mut source = String::from("aag 18 16 1 1 1\n");
        for variable in 1..=16 {
            source.push_str(&format!("{}\n", variable * 2));
        }
        source.push_str("34 2 0\n36\n36 4 2\n");
        for input in 0..16 {
            source.push_str(&format!("i{input} sensor_{input}\n"));
        }
        source.push_str("l0 mode\no0 conflicting_primary_sensors\nc\nwide sparse fixture\n");
        source.into_bytes()
    }

    fn wide_dense_aiger_fixture() -> Vec<u8> {
        dense_support_aiger_fixture(9)
    }

    fn dense_support_aiger_fixture(relevant: usize) -> Vec<u8> {
        assert!((2..=16).contains(&relevant));
        let gates = relevant - 1;
        let maximum = 17 + gates;
        let mut source = format!("aag {maximum} 16 1 1 {gates}\n");
        for variable in 1..=16 {
            source.push_str(&format!("{}\n", variable * 2));
        }
        source.push_str(&format!("34 2 0\n{}\n", maximum * 2));
        let mut accumulated = 2usize;
        for (gate, input) in (1..relevant).enumerate() {
            let output = (18 + gate) * 2;
            source.push_str(&format!("{output} {accumulated} {}\n", (input + 1) * 2));
            accumulated = output;
        }
        source.extend(std::iter::once('c'));
        source.push_str("\nwide dense fixture\n");
        source.into_bytes()
    }

    #[test]
    fn binary_aiger_import_matches_ascii_semantics() {
        let ascii = b"aag 4 2 1 1 1\n2\n4\n6 6 0\n8\n8 4 2\ni0 left_request\ni1 right_request\nl0 state\no0 simultaneous_request\nc\nfixture\n";
        let expected = parse_aiger_bytes(ascii).unwrap();
        let actual = parse_aiger_bytes(&binary_aiger_fixture()).unwrap();
        assert_eq!(actual, expected);

        let encoding = aag_bmc_encoding(&actual, 2).unwrap();
        let run = run_aag_bmc(&actual, 2, &encoding).unwrap();
        assert!(run.first_sat_query.is_some());
        assert!(run.witnesses_valid);
    }

    #[test]
    fn interface_quotient_repairs_locally_and_recovers_an_avoiding_trace() {
        let model = parse_aiger_bytes(&binary_aiger_fixture()).unwrap();
        let table = AagInterfaceTable::compile(&model).unwrap();
        let mut tree = InterfaceQuotientTree::new(&table, 1).unwrap();
        let mut constraints = vec![vec![None; 2]; 2];

        constraints[1] = vec![Some(true), Some(true)];
        assert!(
            tree.query_avoiding(&model, 0, &constraints, true)
                .unwrap()
                .witness
                .is_none()
        );

        constraints[1][1] = None;
        let recovered_outcome = tree.query_avoiding(&model, 0, &constraints, true).unwrap();
        let recovered = recovered_outcome.witness.unwrap();
        assert_eq!(recovered.states, vec![0, 0]);
        assert_eq!(recovered.inputs[1] & 1, 1);
        assert_eq!(recovered.inputs[1] >> 1 & 1, 0);
        assert_eq!(recovered_outcome.repaired_leaves, 0); // terminal-only change
        assert_eq!(recovered_outcome.repaired_internal_nodes, 0);

        constraints[0][0] = Some(true);
        let repaired_outcome = tree.query_avoiding(&model, 0, &constraints, true).unwrap();
        let repaired = repaired_outcome.witness.unwrap();
        // This input does not affect the latch transition, so the semantic leaf
        // quotient is unchanged and no ancestor is needlessly recomposed.
        assert_eq!(repaired_outcome.repaired_leaves, 0);
        assert_eq!(repaired_outcome.repaired_internal_nodes, 0);
        for (input, constraint) in repaired.inputs.iter().zip(&constraints).take(2) {
            assert!(table.input_allowed(*input, constraint));
        }
        assert_eq!(
            table.next[repaired.states[0]][repaired.inputs[0]],
            repaired.states[1]
        );
        assert_eq!(
            table.bad_masks[repaired.states[1]][repaired.inputs[1]] & 1,
            0
        );

        let input_driven = parse_aiger_bytes(b"aag 2 1 1 1 0\n2\n4 2 0\n4\n").unwrap();
        let driven_table = AagInterfaceTable::compile(&input_driven).unwrap();
        let mut driven_tree = InterfaceQuotientTree::new(&driven_table, 1).unwrap();
        let driven_constraints = vec![vec![Some(true)], vec![None]];
        let driven = driven_tree
            .query_avoiding(&input_driven, 0, &driven_constraints, true)
            .unwrap();
        assert_eq!(driven.repaired_leaves, 1);
        assert_eq!(driven.repaired_internal_nodes, 1);
    }

    #[test]
    fn interface_projection_is_exact_for_sixteen_declared_inputs() {
        let model = parse_aiger_bytes(&wide_sparse_aiger_fixture()).unwrap();
        let table = AagInterfaceTable::compile(&model).unwrap();
        assert_eq!(table.declared_input_count, 16);
        assert_eq!(table.projected_inputs, vec![0, 1]);
        assert_eq!(table.input_count, 2);

        for state in 0..2usize {
            for declared in 0..=u16::MAX {
                let declared = u64::from(declared);
                let projected = table.project_input(declared);
                assert_eq!(table.next[state][projected], usize::from(declared & 1 == 1));
                assert_eq!(
                    table.bad_masks[state][projected] & 1 != 0,
                    declared & 0b11 == 0b11
                );
            }
        }

        let constraints = vec![vec![None; 2]; 2];
        let mut tree = InterfaceQuotientTree::new(&table, 1).unwrap();
        let witness = tree
            .query_avoiding(&model, 0, &constraints, true)
            .unwrap()
            .witness
            .unwrap();
        assert!(validate_interface_witness(
            &model,
            &table,
            0,
            &constraints,
            &witness
        ));
        assert!(witness.declared_inputs.iter().all(|input| input >> 2 == 0));
    }

