    #[test]
    fn interface_projection_handles_bit_sixty_three_and_rejects_sixty_five_inputs() {
        let mut boundary = String::from("aag 66 64 1 1 1\n");
        for variable in 1..=64 {
            boundary.push_str(&format!("{}\n", variable * 2));
        }
        boundary.push_str("130 2 0\n132\n132 128 2\nc\n64-input boundary\n");
        let model = parse_aiger_bytes(boundary.as_bytes()).unwrap();
        let table = AagInterfaceTable::compile(&model).unwrap();
        assert_eq!(table.declared_input_count, 64);
        assert_eq!(table.projected_inputs, vec![0, 63]);
        assert_eq!(table.project_input((1u64 << 63) | 1), 0b11);
        assert_eq!(table.lift_input(0b10), 1u64 << 63);

        let mut excessive = String::from("aag 66 65 1 1 0\n");
        for variable in 1..=65 {
            excessive.push_str(&format!("{}\n", variable * 2));
        }
        excessive.push_str("132 2 0\n2\nc\n65-input rejection\n");
        let model = parse_aiger_bytes(excessive.as_bytes()).unwrap();
        assert!(
            AagInterfaceTable::compile(&model)
                .unwrap_err()
                .contains("1..=64 declared inputs")
        );
    }

    #[test]
    fn interface_relation_composition_is_exact() {
        let mut left = InterfaceRelation::empty(4);
        left.insert(0, 1);
        left.insert(0, 2);
        left.insert(3, 0);
        let mut right = InterfaceRelation::empty(4);
        right.insert(1, 3);
        right.insert(2, 0);
        right.insert(0, 2);
        let composed = InterfaceRelation::compose(&left, &right).unwrap();
        assert_eq!(composed.targets(0).collect::<Vec<_>>(), vec![0, 3]);
        assert_eq!(composed.targets(3).collect::<Vec<_>>(), vec![2]);
        assert_eq!(composed.pairs(), 3);
    }

    #[test]
    fn binary_aiger_rejects_malformed_delta_streams() {
        let mut truncated = b"aig 3 1 1 1 1\n2 0\n6\n".to_vec();
        truncated.push(0x80);
        assert!(
            parse_aiger_bytes(&truncated)
                .unwrap_err()
                .contains("truncated binary AIGER delta")
        );

        let mut underflow = b"aig 3 1 1 1 1\n2 0\n6\n".to_vec();
        underflow.extend([7, 0]);
        assert!(
            parse_aiger_bytes(&underflow)
                .unwrap_err()
                .contains("invalid binary AIGER first delta")
        );

        let mut overflow = b"aig 3 1 1 1 1\n2 0\n6\n".to_vec();
        overflow.extend(std::iter::repeat_n(0xff, (usize::BITS as usize / 7) + 1));
        assert!(
            parse_aiger_bytes(&overflow)
                .unwrap_err()
                .contains("binary AIGER delta overflow")
        );
    }

